def call_twice(func, arg):
    print(func(arg))
    print(func(arg))

call_twice(greet, "Python")

def loud(func):
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        return f"*** {result} ***"
    return wrapper

@loud
def say_hello(name):
    return f"Hello, {name}"

print(say_hello("Python"))

def bold(func):
    def wrapper(*args, **kwargs):
        return f"<b>{func(*args, **kwargs)}</b>"
    return wrapper

def italic(func):
    def wrapper(*args, **kwargs):
        return f"<i>{func(*args, **kwargs)}</i>"
    return wrapper

@bold
@italic
def greet(name):
    return f"Hello, {name}"

print(greet("Python"))

class Circle:
    def __init__(self, radius):
        self.radius = radius

    @property
    def area(self):
        return 3.14159 * self.radius ** 2

    @property
    def circumference(self):
        return 2 * 3.14159 * self.radius

c = Circle(5)
print(f"Area: {c.area:.2f}")
print(f"Circumference: {c.circumference:.2f}")

import random
random.seed(42)

def retry(times):
    def decorator(func):
        def wrapper(*args, **kwargs):
            for attempt in range(1, times + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    print(f"Attempt {attempt} failed: {e}")
                    if attempt == times:
                        raise
        return wrapper
    return decorator

call_count = 0

@retry(times=5)
def flaky_api():
    global call_count
    call_count += 1
    if call_count < 3:
        raise ConnectionError("Server timeout")
    return "Success!"

result = flaky_api()
print(result)
